    function clone(value) {
        return JSON.parse(JSON.stringify(value));
    }

    function ensureInt(value, name) {
        if (typeof value !== 'number' || value % 1 !== 0) {
            throw new Error(name + ' must be an integer');
        }
    }

    function pointKey(point) {
