            throw new Error(name + ' must be [x, y]');
        }

        ensureInt(point[0], name + '[0]');
        ensureInt(point[1], name + '[1]');

        if (point[0] < 0 || point[0] >= width || point[1] < 0 || point[1] >= height) {
            throw new Error(name + ' is out of bounds');
        }
    }

    function validateScenario(raw) {
        var seenWalls = {};

        if (!raw || typeof raw !== 'object') {
            throw new Error('Scenario data must be an object');
        }

        var scenario = {
            width: raw.width,
            height: raw.height,
            walls: raw.walls,
            start: raw.start,
            end: raw.end
        };

        ensureInt(scenario.width, 'width');
        ensureInt(scenario.height, 'height');

        if (scenario.width <= 0 || scenario.height <= 0) {
            throw new Error('width/height must be positive');
        }

        if (!Array.isArray(scenario.walls)) {
            throw new Error('walls must be an array');
        }

        ensurePoint(scenario.start, scenario.width, scenario.height, 'start');
        ensurePoint(scenario.end, scenario.width, scenario.height, 'end');

        scenario.walls.forEach(function(point, index) {
            var key;

