            if (pointsEqual(point, scenario.start) || pointsEqual(point, scenario.end)) {
                throw new Error('walls cannot include start/end point');
            }

            key = pointKey(point);
            if (seenWalls[key]) {
                throw new Error('walls contain duplicate point: ' + key);
            }
            seenWalls[key] = true;
