        gridState = {
            width: 15,
            height: 15,
            walls: [
                [1, 1],
                [2, 2],
                [3, 4]
            ],
            start: [0, 0],
            end: [14, 14]
        };
    });

    it('should save scenario as JSON string with required fields', function() {
        var saved = scenario.saveScenario(gridState);
        saved.should.be.a.String();

        var parsed = JSON.parse(saved);
        parsed.width.should.equal(15);
        parsed.height.should.equal(15);
        parsed.walls.should.eql(gridState.walls);
        parsed.start.should.eql(gridState.start);
        parsed.end.should.eql(gridState.end);
    });

    it('should load scenario from saved JSON without data loss', function() {
        var saved = scenario.saveScenario(gridState);
        var loaded = scenario.loadScenario(saved);
        loaded.should.eql(gridState);
    });

    it('should load scenario from parsed JSON object input', function() {
        var parsed = JSON.parse(scenario.saveScenario(gridState));
        var loaded = scenario.loadScenario(parsed);

        loaded.should.eql(gridState);
        loaded.should.not.equal(parsed);
    });

    it('should reject invalid scenario JSON format', function() {
        (function() {
            scenario.loadScenario('{"width":15}');
        }).should.throw();

        (function() {
            scenario.loadScenario('{"width":15,"height":15,"walls":[],"start":[0],"end":[14,14]}');
        }).should.throw();

        (function() {
            scenario.loadScenario('{"width":15,"height":15,"walls":[[15,0]],"start":[0,0],"end":[14,14]}');
        }).should.throw();

        (function() {
            scenario.loadScenario('{"width":15,"height":15,"walls":[[0,0]],"start":[0,0],"end":[14,14]}');
        }).should.throw();

        (function() {
