127	    function uniqueWalls(walls, start, end) {
128	        var seen = {};
129	        var result = [];
130	
131	        walls.forEach(function(point) {
132	            var key = pointKey(point);
133	            if (!seen[key] && !pointsEqual(point, start) && !pointsEqual(point, end)) {
