146	    function generateMazePreset() {
147	        var preset = createEmptyScenario();
148	        var walls = [];
149	        var verticalGaps = {2: 1, 4: 11, 6: 5, 8: 9, 10: 3, 12: 13};
150	        var horizontalGaps = {2: 3, 4: 9, 6: 1, 8: 11, 10: 5, 12: 13};
151	
152	        for (var x = 2; x <= 12; x += 2) {
153	            for (var y = 0; y < PRESET_SIZE; y += 1) {
154	                if (y !== verticalGaps[x]) {
155	                    walls.push([x, y]);
156	                }
157	            }
158	        }
159	
160	        for (var yRow = 2; yRow <= 12; yRow += 2) {
161	            for (var xCol = 0; xCol < PRESET_SIZE; xCol += 1) {
162	                if (xCol !== horizontalGaps[yRow]) {
163	                    walls.push([xCol, yRow]);
164	                }
165	            }
166	        }
167	
168	        preset.walls = uniqueWalls(walls, preset.start, preset.end);
169	        return preset;
170	    }
