172	    function generateSpiralPreset() {
173	        var preset = createEmptyScenario();
174	        var walls = [];
175	        var left = 1;
176	        var right = PRESET_SIZE - 2;
177	        var top = 1;
178	        var bottom = PRESET_SIZE - 2;
179	
180	        while (left <= right && top <= bottom) {
181	            for (var x = left; x <= right; x += 1) {
182	                walls.push([x, top]);
183	            }
184	
185	            for (var y = top + 1; y <= bottom; y += 1) {
186	                walls.push([right, y]);
187	            }
188	
189	            if (top < bottom) {
190	                for (x = right - 1; x >= left; x -= 1) {
191	                    walls.push([x, bottom]);
192	                }
193	            }
194	
195	            if (left < right) {
196	                for (y = bottom - 1; y > top + 1; y -= 1) {
197	                    walls.push([left, y]);
198	                }
199	            }
200	
201	            left += 2;
202	            right -= 2;
203	            top += 2;
204	            bottom -= 2;
205	        }
206	
207	        preset.walls = uniqueWalls(walls, preset.start, preset.end);
208	        return preset;
209	    }
