227	    function shuffleInPlace(items) {
228	        for (var i = items.length - 1; i > 0; i -= 1) {
229	            var j = Math.floor(Math.random() * (i + 1));
230	            var temp = items[i];
231	            items[i] = items[j];
232	            items[j] = temp;
233	        }
234	    }
